import React, { Component } from 'react';
import { connect }  from 'react-redux';
import { Link } from 'react-router-dom';
import '../styles/HeaderStyles.css';
import IconButton from '@material-ui/core/IconButton';
import BugReportIcon from '@material-ui/icons/BugReport';
import AccountCircleIcon from '@material-ui/icons/AccountCircle';

class Header extends Component {
  renderContent() {
    switch(this.props.auth) {
      case null:
        return;
      case false:
        return (
          <div className='nav'>
          <IconButton edge="start">
            <Link to='/projects' className='link icon'><BugReportIcon fontSize="large" /></Link>
          </IconButton>
          <div className="link trackerly">
            <Link to='/' className='link parkly'>Bug Trackerly</Link>              
          </div>
          <div className="dropdown">
              <Link to='/user/:id' className="dropBtn" style={{ textDecoration: "none", color: "white" }}>
                  <AccountCircleIcon fontSize="large" />
              </Link>
              <div className="dropdownContent">
                  <Link to='/bugs' style={{ textDecoration: "none", color: "white" }}>My Bugs</Link>
                  <Link to='/user/:id' style={{ textDecoration: "none", color: "white" }}>Account</Link>
                  <Link to='/signIn'style={{ textDecoration: "none", color: "white" }}>Auth</Link>
              </div>
          </div>
          </div>
        );
      default: 
          return [
            <div className="nav">
              <div className="">Bug Trackerly</div>
            </div>
          ]
    }
  }
}


